import Layout from '../components/layout';
import {graphql} from 'gatsby';
import React from 'react';
import Box from '@mui/material/Box';
import Paper from '@mui/material/Paper';
import Grid from '@mui/material/Unstable_Grid2';
import Typography from '@mui/material/Typography';
import Divider from '@mui/material/Divider';
import Breadcrumbs from '@mui/material/Breadcrumbs';
import Link from '@mui/material/Link';
import Seo from '../components/seo';

const ProductDetailsPage = ({data}) => {
  const product = data.strapiProduct;

  let html = product.content.data.childMarkdownRemark.html;
  if(product.content.medias&&product.content.medias.length){
    product.content.medias.forEach(item => {
      const reg = new RegExp(`(<img src="${item.src}".*?">)`, 'g');
      html=html.replaceAll(reg, `<div class="image-wrapper"><img src="${item.localFile.publicURL}"></div>`);

    });
  }


  return (
      <Layout>
        <Box sx={{mt: 2}}>
          <Paper sx={{mr: 2, ml: 2, pr: 1, pl: 1,pb:2}} elevation={2}>
            <Breadcrumbs sx={{pt: 2, pl: 2, pr: 2}} aria-label="breadcrumb">
              <Link underline="hover" color="inherit" href="/">
                首页
              </Link>
              <Link
                  underline="hover"
                  color="inherit"
                  href="/product"
              >
                产品中心
              </Link>
              <Typography color="text.primary">{product.title}</Typography>
            </Breadcrumbs>
            <Grid container>
              <Grid item xs={12} md={12} display="flex" justifyContent="center">
                <Typography sx={{mt: 4, mb: 2}} variant="h4" component="div">
                  {product.title}
                </Typography>
              </Grid>

            </Grid>
            <Divider/>
            <Grid sx={{mt: 2}} container spacing={2} display="flex"
                  justifyContent="center">
              <img loading="lazy" src={product?.image?.localFile.publicURL} style={{objectFit:'cover',maxWidth:'100%'}} />
            {/*  <GatsbyImage
                  image={getImage(product?.image?.localFile)}
                  alt={product?.title}
              />*/}
            </Grid>
            <Grid className='markdown' sx={{overflowX: 'auto', ml: 1, mr: 1}}
                  dangerouslySetInnerHTML={{__html: html}}>

            </Grid>
          </Paper>


        </Box>

      </Layout>
  );
};

export const pageQuery = graphql`
  query ($id: String) {
    strapiProduct(id: {eq: $id}) {
    content {
    medias {
      src
        localFile {
         
          publicURL
        }
      }
      data {
         childMarkdownRemark {
          html
        }
      }
    }
    title
    time
    description
    keywords
    image {
      localFile {
         publicURL
        childImageSharp {
          gatsbyImageData
        }
      }
    }
  }
  }
`;
export const Head = ({ data }) => <Seo title={data.strapiProduct.title}
                                       keywords={data.strapiProduct.keywords}
                                       description={data.strapiProduct.description}/>;
export default ProductDetailsPage;
